        activeCarts = await refreshActiveCarts({
          cartUrl,
          lastResult: result,
          retailer: ASKET_RETAILER,
          stagedCount,
        });
      }
    }
  }

  return {
    action: "asket_staging_result",
    activeCarts,
    cartUrl,
    resultCard: await renderResultCard({
      cartUrl,
      results,
      stagedCount,
      totalSelected: candidates.length,
    }),
    results,
    stagedCount,
    totalSelected: candidates.length,
  };
